using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    Ptr documents = app->documents();
    if (!documents)
        return false;

    Ptr doc = documents->add(DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    Ptr product = app->activeProduct();
    if (!product)
        return false;

    Ptr design = product;
    if (!design)
        return false;

    // Get the root component of the active design.
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Create sketch
    Ptr sketches = rootComp->sketches();
    if (!sketches)
        return false;
    Ptr sketch = sketches->add(rootComp->xZConstructionPlane());
    if (!sketch)
        return false;
    Ptr sketchCurves = sketch->sketchCurves();
    if (!sketchCurves)
        return false;
    Ptr sketchLines = sketchCurves->sketchLines();
    if (!sketchLines)
        return false;
    Ptr startPoint = adsk::core::Point3D::create(0, 0, 0);
    if (!startPoint)
        return false;
    Ptr endPoint = adsk::core::Point3D::create(5, 5, 0);
    if (!endPoint)
        return false;
    sketchLines->addTwoPointRectangle(startPoint, endPoint);

    // Get the profile defined by the rectangle.
    Ptr profiles = sketch->profiles();
    if (!profiles)
        return false;
    Ptr prof = profiles->item(0);
    if (!prof)
        return false;

    // Create an extrusion input.
    Ptr features = rootComp->features();
    if (!features)
        return false;
    Ptr extrudes = features->extrudeFeatures();
    if (!extrudes)
        return false;
    Ptr extInput =
        extrudes->createInput(prof, adsk::fusion::FeatureOperations::NewBodyFeatureOperation);
    if (!extInput)
        return false;

    // Define that the extent is a distance extent of 5 cm.
    Ptr distance = adsk::core::ValueInput::createByReal(5);
    if (!distance)
        return false;
    extInput->setDistanceExtent(false, distance);

    // Create the extrusion.
    Ptr ext = extrudes->add(extInput);
    if (!ext)
        return false;

    // Get the body created by extrusion.
    Ptr bodies = ext->bodies();
    if (!bodies)
        return false;
    Ptr body = bodies->item(0);
    if (!body)
        return false;

    // Create unstitch feature.
    Ptr unstitchFeatures = features->unstitchFeatures();
    if (!unstitchFeatures)
        return false;
    Ptr entities = adsk::core::ObjectCollection::create();
    if (!entities)
        return false;
    entities->add(body);
    Ptr unstitch = unstitchFeatures->add(entities);


    return true;
}
